B.Hh=new A.ar("Following the gear malfunction, the captain decided to abort the landing.","\u0130ni\u015f tak\u0131m\u0131 ar\u0131zas\u0131n\u0131n ard\u0131ndan kaptan ini\u015fi iptal etmeye karar verdi.","abort")
B.SX=s([B.HB,B.HV,B.Hh],t.l)
