B.NL=new A.J(B.A,"\u2708\ufe0f Primary Flight Instruments","**ADI (Attitude Director Indicator)** \u2014 shows pitch and bank\n**HSI (Horizontal Situation Indicator)** \u2014 combined heading + navigation\n**VSI (Vertical Speed Indicator)** \u2014 rate of climb/descent in feet per minute\n**ASI (Airspeed Indicator)** \u2014 shows IAS in knots\n**Altimeter** \u2014 shows altitude using static pressure\n**Turn & Slip Indicator** \u2014 shows rate of turn and coordination",null,null,null)
B.Np=new A.J(B.A,"\ud83d\udef0\ufe0f Navigation Systems","**FMS (Flight Management System)** \u2014 computerized navigation, flight planning, and performance\n**GPS (Global Positioning System)** \u2014 satellite-based positioning\n**IRS/INS (Inertial Reference System)** \u2014 self-contained navigation using accelerometers\n**DME (Distance Measuring Equipment)** \u2014 ground-based range measurement\n**ADF (Automatic Direction Finder)** \u2014 homes to NDB stations\n**TCAS II** \u2014 provides Resolution Advisories (RA) to avoid traffic",null,null,null)
B.GQ=new A.ar("The FMS automatically calculates the most fuel-efficient cruise altitude.","FMS, en yak\u0131t verimli seyir irtifas\u0131n\u0131 otomatik olarak hesaplar.","FMS")
B.Hf=new A.ar("A TCAS Resolution Advisory directed the crew to climb immediately.","Bir TCAS \xc7\xf6z\xfcm Tavsiyesi, ekibi hemen t\u0131rmanmaya y\xf6neltti.","Resolution Advisory")
B.GO=new A.ar("The IRS requires an alignment period of approximately 10 minutes before departure.","IRS, kalk\u0131\u015ftan \xf6nce yakla\u015f\u0131k 10 dakikal\u0131k bir hizalama s\xfcresi gerektirir.","alignment period")
