B.SV=s(["Immediately after","At the same time as","Before","In preparation for"],t.s)
B.Yd=new A.a1(-242,B.aM,452,'"Prior to engine start, all doors must be closed and armed." The phrase "prior to" means:',B.SV,2,B.D,null,null,null)
B.Q7=s(["Similar to","According to and following","Despite","Approximately matching"],t.s)
