B.Tl=s(["Vectors will definitely be given by ATC","The pilot should anticipate radar vectors but fly published procedure if not given","Vectors are not available on this route","The pilot may request vectors"],t.s)
B.Z4=new A.a1(-272,B.ak,642,'"Expect vectors" on a STAR means:',B.Tl,1,B.aH,null,null,null)
B.PO=s(["Climb to speed 220 knots","Maintain 220 KIAS or less","Set Mach 0.220","Not exceed 220 feet per minute climb"],t.s)
B.YB=new A.a1(-273,B.ak,643,'If a SID shows "S220" at a waypoint, the crew must:',B.PO,1,B.aH,null,null,null)
